    14: "\n(function(){\n  function ensureRoutesInHeader(){\n    var routes = document.getElementById('routes');\n    var header = document.querySelector('header') || document.getElementById('app') || document.body;\n    var bar = document.getElementById('bottom-bar');\n    if(!routes) return;\n    if(bar && bar.contains(routes)){\n      // Move routes back to header, at the beginning\n      if(header.firstChild) header.insertBefore(routes, header.firstChild);\n      else header.appendChild(routes);\n    }\n  }\n  function init(){\n    ensureRoutesInHeader();\n  }\n  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', init);\n  else init();\n  // Also re-check after other scripts run\n  setTimeout(init, 200);\n  setTimeout(init, 800);\n  setTimeout(init, 1600);\n})();\n",
    15: "\n(function(){\n  function findHeader(){\n    return document.querySelector('header') || document.getElementById('app') || document.body;\n  }\n  function qInHeader(sel){\n    var h = findHeader();\n    return h ? h.querySelector(sel) : null;\n  }\n  function reorder(){\n    var header = findHeader();\n    if(!header) return;\n    var routes = document.getElementById('routes');\n    if(!routes || !header.contains(routes)) return;\n\n    // Find \"Storia\" and \"Abbonamento\" buttons in the header\n    var storia = qInHeader('[title*=\"Storia\" i], [aria-label*=\"Storia\" i], #storia, .storia, button[data-key=\"storia\"]');\n    var abbon = qInHeader('[title*=\"Abbon\" i], [aria-label*=\"Abbon\" i], #abbonamento, .abbonamento, button[data-key=\"abbonamento\"]');\n\n    if(storia && abbon){\n      // Insert routes before Abbonamento so it's between Storia and Abbonamento\n      if(abbon.parentNode){\n        abbon.parentNode.insertBefore(routes, abbon);\n        return;\n      }\n    }\n    if(storia && storia.parentNode){\n      // Fallback: place routes right after Storia\n      if(storia.nextSibling){\n        storia.parentNode.insertBefore(routes, storia.nextSibling);\n      }else{\n        storia.parentNode.appendChild(routes);\n      }\n    }\n  }\n  function init(){\n    reorder();\n  }\n  if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);\n  else init();\n  // retry in case toolbar items mount late\n  setTimeout(init, 200);\n  setTimeout(init, 800);\n  setTimeout(init, 1600);\n})();\n",
    
    19: "\n(function(){\n  function ready(cb){\n    if(document.readyState === 'loading'){\n      document.addEventListener('DOMContentLoaded', cb, {once:true});\n    } else cb();\n  }\n\n  function getLang(){\n    try{\n      return localStorage.getItem('lang') || document.documentElement.getAttribute('lang') || 'it';\n    }catch(_){\n      return document.documentElement.getAttribute('lang') || 'it';\n    }\n  }\n\n  var LBL = {\n    it:['Mostra QR','Nascondi QR'],\n    en:['Show QR','Hide QR'],\n    es:['Mostrar QR','Ocultar QR'],\n    fr:['Afficher QR','Masquer QR'],\n    ar:['إظهار QR','إخفاء QR'],\n    ru:['Показать QR','Скрыть QR'],\n    zh:['显示 QR','隐藏 QR'],\n    lij:['Mostra QR','Ascundi QR']\n  };\n\n  function labelFor(on){\n    var lang = (getLang()||'it').toLowerCase();\n    var base = lang.split('-')[0];\n    var pair = LBL[lang] || LBL[base] || LBL.it;\n    return on ? pair[1] : pair[0];\n  }\n\n  function masterChk(){ return document.getElementById('chk-qr-all'); }\n\n  \n\n  function isOn(){\n    try{\n      return !!(window.map && window.QR_ALL && window.map.hasLayer(window.QR_ALL));\n    }catch(_){\n      return false;\n    }\n  }\nfunction createQrBtn(){\n    var btn = document.getElementById('btn-qr-removed');\n    if(btn) return btn;\n\n    btn = document.createElement('button');\n    btn.id = 'btn-qr-removed';\n    btn.type = 'button';\n    btn.className = 'qt-item qt-cat qt-pill qt-pill-qr';\n    btn.innerHTML = '<span aria-hidden=\"true\" class=\"qt-icon\"><img alt=\"\" draggable=\"false\" height=\"32\" src=\"toolbar/qr.svg\" width=\"32\"/></span><span class=\"sr-only\">QR</span>';\n\n    btn.addEventListener('click', function(ev){\n      ev.preventDefault();\n      ev.stopPropagation();\n      try{\n        var on = isOn();\n        if(typeof window.__qrToggleAll === 'function'){\n          window.__qrToggleAll(!on);\n        }else if(typeof window.toggleQR === 'function'){\n          window.toggleQR();\n        }else{\n          // Fallback: toggle the master checkbox if it exists\n          var m = masterChk();\n          if(m){\n            m.checked = !m.checked;\n            m.dispatchEvent(new Event('change', {bubbles:true}));\n          }\n        }\n      }catch(_){ }\n      setTimeout(syncLabel, 0);\n    });\n\n    return btn;\n  }\n\n  function syncLabel(){\n    var btn = document.getElementById('btn-qr-removed');\n    if(!btn) return;\n    var on = isOn();\n    try{\n      var m = masterChk();\n      if(m) m.checked = on;\n    }catch(_){ }\n    var t  = labelFor(on);\n    btn.title = t;\n    btn.setAttribute('aria-label', t);\n    // Visual state: highlight when active\n    btn.classList.toggle('is-active', on);\n  }\n\n  function placeQrBtn(){\n    var rail = document.getElementById('quick-toggles');\n    if(!rail) return;\n\n    var btn = createQrBtn();\n\n    // Se era finito nella toolbar, toglilo da lì\n    try{\n      var bar = document.querySelector('.toolbar-buttons');\n      if(bar && bar.contains(btn)) bar.removeChild(btn);\n    }catch(_){}\n\n    // Mettilo in alto nella colonna destra (prima delle pillole categorie)\n    if(rail.firstElementChild !== btn){\n      rail.insertBefore(btn, rail.firstElementChild);\n    }\n    syncLabel();\n  }\n\n  ready(function(){\n    placeQrBtn();\n\n    // Mantieni il bottone in posizione anche se il DOM viene ricreato\n    var obs = new MutationObserver(function(){\n      placeQrBtn();\n    });\n    try{\n      obs.observe(document.getElementById('map') || document.body, {childList:true, subtree:true});\n    }catch(_){}\n\n    var m = masterChk();\n    if(m){\n      m.addEventListener('change', syncLabel);\n    }\n  });\n})();\n",
